271			sb := text.NewBuilder()
272	
273			// We have to do this to prevent the shell from misidentifying escape sequences.
274			for _, char := range title {
275				escaped, shouldEscape := formats.EscapeSequences[char]
276				if shouldEscape {
277					sb.WriteString(escaped)
278					continue
279				}
280	
281				sb.WriteRune(char)
282			}
283	
284			return fmt.Sprintf(formats.Title, sb.String())
285		default:
286			return fmt.Sprintf(formats.Title, trimAnsi(title))
287		}
288	}
